CREATE OR REPLACE FUNCTION catalog.post_article_creer(p_params jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
BEGIN
  INSERT INTO catalog.article (reference, designation, description, categorie_id, unite, prix_vente, prix_achat, tva)
  VALUES (
    nullif(trim(p_params->>'reference'), ''),
    trim(p_params->>'designation'),
    nullif(trim(p_params->>'description'), ''),
    nullif(p_params->>'categorie_id', '')::int,
    coalesce(nullif(p_params->>'unite', ''), 'u'),
    nullif(p_params->>'prix_vente', '')::numeric,
    nullif(p_params->>'prix_achat', '')::numeric,
    coalesce(nullif(p_params->>'tva', '')::numeric, 20.00)
  ) RETURNING id INTO v_id;

  RETURN pgv.toast(pgv.t('catalog.toast_article_created'))
    || pgv.redirect(pgv.call_ref('get_article', jsonb_build_object('p_id', v_id)));
END;
$function$;
COMMENT ON FUNCTION catalog.post_article_creer(jsonb) IS 'Créer un article';

CREATE OR REPLACE FUNCTION catalog.post_article_modifier(p_params jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_params->>'id')::int;
BEGIN
  IF v_id IS NULL THEN
    RETURN pgv.toast(pgv.t('catalog.err_id_missing'), 'error');
  END IF;

  -- Modification partielle (toggle actif) ou complète
  IF p_params ? 'designation' THEN
    UPDATE catalog.article SET
      reference = nullif(trim(p_params->>'reference'), ''),
      designation = trim(p_params->>'designation'),
      description = nullif(trim(p_params->>'description'), ''),
      categorie_id = nullif(p_params->>'categorie_id', '')::int,
      unite = coalesce(nullif(p_params->>'unite', ''), 'u'),
      prix_vente = nullif(p_params->>'prix_vente', '')::numeric,
      prix_achat = nullif(p_params->>'prix_achat', '')::numeric,
      tva = coalesce(nullif(p_params->>'tva', '')::numeric, 20.00),
      updated_at = now()
    WHERE id = v_id;
  ELSE
    UPDATE catalog.article SET
      actif = coalesce((p_params->>'actif')::boolean, actif),
      updated_at = now()
    WHERE id = v_id;
  END IF;

  RETURN pgv.toast(pgv.t('catalog.toast_article_modified'))
    || pgv.redirect(pgv.call_ref('get_article', jsonb_build_object('p_id', v_id)));
END;
$function$;
COMMENT ON FUNCTION catalog.post_article_modifier(jsonb) IS 'Modifier un article (champs complets ou partiel actif/inactif)';

CREATE OR REPLACE FUNCTION catalog.post_categorie_creer(p_params jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  INSERT INTO catalog.categorie (nom, parent_id)
  VALUES (
    trim(p_params->>'nom'),
    nullif(p_params->>'parent_id', '')::int
  );

  RETURN pgv.toast(pgv.t('catalog.toast_categorie_created'))
    || pgv.redirect(pgv.call_ref('get_categories'));
END;
$function$;
COMMENT ON FUNCTION catalog.post_categorie_creer(jsonb) IS 'Créer une catégorie';

GRANT USAGE ON SCHEMA catalog TO anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA catalog TO anon;

-- Schema: catalog_ut
CREATE SCHEMA IF NOT EXISTS catalog_ut;

CREATE OR REPLACE FUNCTION catalog_ut.test_pages_render()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
  v_cat_id int;
  v_art_id int;
BEGIN
  -- Setup minimal data
  INSERT INTO catalog.categorie (nom) VALUES ('UT Render Cat') RETURNING id INTO v_cat_id;
  INSERT INTO catalog.article (designation, reference, categorie_id, prix_vente, unite, tva)
  VALUES ('UT Render Art', 'UT-REND-01', v_cat_id, 50.00, 'u', 20.00) RETURNING id INTO v_art_id;

  PERFORM set_config('pgv.route_prefix', '/catalog', true);

  -- get_index
  v_html := catalog.get_index();
  RETURN NEXT ok(v_html IS NOT NULL, 'get_index renders');
  RETURN NEXT ok(v_html LIKE '%pgv-stat%', 'get_index has stats');

  -- get_articles
  v_html := catalog.get_articles();
  RETURN NEXT ok(v_html IS NOT NULL, 'get_articles renders');
  RETURN NEXT ok(v_html LIKE '%UT-REND-01%', 'get_articles shows test article');

  -- get_articles with search
  v_html := catalog.get_articles(jsonb_build_object('q', 'Render'));
  RETURN NEXT ok(v_html LIKE '%UT-REND-01%', 'get_articles search works');

  -- get_article
  v_html := catalog.get_article(v_art_id);
  RETURN NEXT ok(v_html IS NOT NULL, 'get_article renders');
  RETURN NEXT ok(v_html LIKE '%UT Render Art%', 'get_article shows designation');

  -- get_article_form (create)
  v_html := catalog.get_article_form();
  RETURN NEXT ok(v_html IS NOT NULL, 'get_article_form create renders');
  RETURN NEXT ok(v_html LIKE '%post_article_creer%', 'create form targets post_article_creer');

  -- get_article_form (edit)
  v_html := catalog.get_article_form(jsonb_build_object('p_id', v_art_id::text));
  RETURN NEXT ok(v_html IS NOT NULL, 'get_article_form edit renders');
  RETURN NEXT ok(v_html LIKE '%post_article_modifier%', 'edit form targets post_article_modifier');

  -- get_categories
  v_html := catalog.get_categories();
  RETURN NEXT ok(v_html IS NOT NULL, 'get_categories renders');
  RETURN NEXT ok(v_html LIKE '%UT Render Cat%', 'get_categories shows test category');

  -- article_options
  v_html := catalog.article_options();
  RETURN NEXT ok(v_html LIKE '%UT-REND-01%', 'article_options includes test article');

  -- Cleanup
  DELETE FROM catalog.article WHERE reference = 'UT-REND-01';
  DELETE FROM catalog.categorie WHERE nom = 'UT Render Cat';
END;
$function$;
COMMENT ON FUNCTION catalog_ut.test_pages_render() IS 'Test que toutes les pages catalog rendent sans erreur';

CREATE OR REPLACE FUNCTION catalog_ut.test_post_article_creer()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
  v_art catalog.article;
  v_id int;
BEGIN
  -- Create
  v_result := catalog.post_article_creer(jsonb_build_object(
    'reference', 'UT-ART-01', 'designation', 'Article test UT',
    'prix_vente', '100.00', 'prix_achat', '60.00', 'tva', '20.00', 'unite', 'u'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'create returns success toast');
  RETURN NEXT ok(v_result LIKE '%data-redirect%', 'create returns redirect');

  SELECT * INTO v_art FROM catalog.article WHERE reference = 'UT-ART-01';
  RETURN NEXT ok(FOUND, 'article created in DB');
  RETURN NEXT is(v_art.designation, 'Article test UT', 'designation saved');
  RETURN NEXT is(v_art.prix_vente, 100.00::numeric(12,2), 'prix_vente saved');
  RETURN NEXT is(v_art.prix_achat, 60.00::numeric(12,2), 'prix_achat saved');
  RETURN NEXT is(v_art.tva, 20.00::numeric(4,2), 'tva saved');
  RETURN NEXT is(v_art.unite, 'u', 'unite saved');
  RETURN NEXT ok(v_art.actif, 'article actif by default');

  -- Cleanup
  DELETE FROM catalog.article WHERE reference = 'UT-ART-01';
END;
$function$;
COMMENT ON FUNCTION catalog_ut.test_post_article_creer() IS 'Test création article';

CREATE OR REPLACE FUNCTION catalog_ut.test_post_article_modifier()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
  v_art catalog.article;
  v_id int;
BEGIN
  -- Setup
  INSERT INTO catalog.article (reference, designation, prix_vente, tva, unite)
  VALUES ('UT-MOD-01', 'A modifier', 50.00, 20.00, 'u') RETURNING id INTO v_id;

  -- Full update
  v_result := catalog.post_article_modifier(jsonb_build_object(
    'id', v_id, 'designation', 'Modifié complet', 'reference', 'UT-MOD-01',
    'prix_vente', '120.00', 'prix_achat', '80.00', 'tva', '10.00', 'unite', 'h'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'full update success');

  SELECT * INTO v_art FROM catalog.article WHERE id = v_id;
  RETURN NEXT is(v_art.designation, 'Modifié complet', 'designation updated');
  RETURN NEXT is(v_art.prix_vente, 120.00::numeric(12,2), 'prix_vente updated');
  RETURN NEXT is(v_art.prix_achat, 80.00::numeric(12,2), 'prix_achat updated');
  RETURN NEXT is(v_art.tva, 10.00::numeric(4,2), 'tva updated');
  RETURN NEXT is(v_art.unite, 'h', 'unite updated');

  -- Toggle actif -> false
  v_result := catalog.post_article_modifier(jsonb_build_object('id', v_id, 'actif', 'false'));
  SELECT * INTO v_art FROM catalog.article WHERE id = v_id;
  RETURN NEXT ok(NOT v_art.actif, 'article deactivated');

  -- Toggle actif -> true
  v_result := catalog.post_article_modifier(jsonb_build_object('id', v_id, 'actif', 'true'));
  SELECT * INTO v_art FROM catalog.article WHERE id = v_id;
  RETURN NEXT ok(v_art.actif, 'article reactivated');

  -- Cleanup
  DELETE FROM catalog.article WHERE id = v_id;
END;
$function$;
COMMENT ON FUNCTION catalog_ut.test_post_article_modifier() IS 'Test modification article (complète + toggle actif)';

CREATE OR REPLACE FUNCTION catalog_ut.test_post_categorie_creer()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
  v_cat catalog.categorie;
  v_parent_id int;
BEGIN
  -- Create root category
  v_result := catalog.post_categorie_creer(jsonb_build_object('nom', 'UT Catégorie Root'));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'create root success');
  RETURN NEXT ok(v_result LIKE '%data-redirect%', 'create returns redirect');

  SELECT * INTO v_cat FROM catalog.categorie WHERE nom = 'UT Catégorie Root';
  RETURN NEXT ok(FOUND, 'root category created');
  RETURN NEXT ok(v_cat.parent_id IS NULL, 'parent_id is null for root');
  v_parent_id := v_cat.id;

  -- Create child category
  v_result := catalog.post_categorie_creer(jsonb_build_object('nom', 'UT Sous-catégorie', 'parent_id', v_parent_id::text));
  SELECT * INTO v_cat FROM catalog.categorie WHERE nom = 'UT Sous-catégorie';
  RETURN NEXT ok(FOUND, 'child category created');
  RETURN NEXT is(v_cat.parent_id, v_parent_id, 'parent_id set correctly');

  -- Cleanup
  DELETE FROM catalog.categorie WHERE nom LIKE 'UT %';
END;
$function$;
COMMENT ON FUNCTION catalog_ut.test_post_categorie_creer() IS 'Test création catégorie';

GRANT USAGE ON SCHEMA catalog_ut TO anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA catalog_ut TO anon;

-- Schema: catalog_qa
CREATE SCHEMA IF NOT EXISTS catalog_qa;

CREATE OR REPLACE FUNCTION catalog_qa.clean()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  DELETE FROM catalog.article;
  DELETE FROM catalog.categorie;
  -- Re-seed
  PERFORM catalog_qa.seed();
END;
$function$;
COMMENT ON FUNCTION catalog_qa.clean() IS 'Nettoyer les données QA du catalog';

CREATE OR REPLACE FUNCTION catalog_qa.seed()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cat_bois int;
  v_cat_quinc int;
  v_cat_isol int;
  v_cat_presta int;
  v_cat_finition int;
BEGIN
  -- Catégories
  INSERT INTO catalog.categorie (nom, ordre) VALUES ('Bois', 1) RETURNING id INTO v_cat_bois;
  INSERT INTO catalog.categorie (nom, ordre) VALUES ('Quincaillerie', 2) RETURNING id INTO v_cat_quinc;
  INSERT INTO catalog.categorie (nom, ordre) VALUES ('Isolation', 3) RETURNING id INTO v_cat_isol;
  INSERT INTO catalog.categorie (nom, ordre) VALUES ('Prestations', 4) RETURNING id INTO v_cat_presta;
  INSERT INTO catalog.categorie (nom, ordre) VALUES ('Finition', 5) RETURNING id INTO v_cat_finition;

  -- Sous-catégories bois
  INSERT INTO catalog.categorie (nom, parent_id, ordre) VALUES ('Bois massif', v_cat_bois, 1);
  INSERT INTO catalog.categorie (nom, parent_id, ordre) VALUES ('Panneaux', v_cat_bois, 2);

  -- Articles Bois
  INSERT INTO catalog.article (reference, designation, description, categorie_id, unite, prix_vente, prix_achat, tva) VALUES
    ('BOIS-CHENE-27', 'Chêne massif 27mm', 'Chêne premier choix, séché, raboté', v_cat_bois, 'm3', 1200.00, 850.00, 20.00),
    ('BOIS-DOUG-45', 'Douglas 45x145 C24', 'Bois de structure Douglas, classé C24', v_cat_bois, 'ml', 8.50, 5.20, 20.00),
    ('BOIS-SAP-22', 'Sapin 22x100 raboté', 'Sapin raboté 4 faces, sec', v_cat_bois, 'ml', 3.20, 1.80, 20.00),
    ('PAN-OSB-18', 'OSB3 18mm 2500x1250', 'Panneau OSB3 milieu humide', v_cat_bois, 'u', 42.00, 32.00, 20.00),
    ('PAN-CP-15', 'Contreplaqué okoumé 15mm', 'Contreplaqué marine okoumé', v_cat_bois, 'u', 65.00, 48.00, 20.00);

  -- Articles Quincaillerie
  INSERT INTO catalog.article (reference, designation, categorie_id, unite, prix_vente, prix_achat, tva) VALUES
    ('QU-VIS-5x50', 'Vis inox A2 5x50 (boîte 200)', v_cat_quinc, 'u', 24.00, 18.50, 20.00),
    ('QU-TIRE-8x80', 'Tirefond 8x80 (boîte 50)', v_cat_quinc, 'u', 32.00, 24.00, 20.00),
    ('QU-EQUER-90', 'Équerre renforcée 90° galva', v_cat_quinc, 'u', 4.80, 3.50, 20.00),
    ('QU-SABOTAB', 'Sabot de solive 50x150', v_cat_quinc, 'u', 3.90, 2.60, 20.00);

  -- Articles Isolation
  INSERT INTO catalog.article (reference, designation, description, categorie_id, unite, prix_vente, prix_achat, tva) VALUES
    ('ISOL-LDB-60', 'Laine de bois 60mm', 'Panneau isolant fibre de bois, lambda 0.038', v_cat_isol, 'm2', 12.50, 8.50, 5.50),
    ('ISOL-LDB-140', 'Laine de bois 140mm', 'Panneau isolant fibre de bois, lambda 0.038', v_cat_isol, 'm2', 28.00, 19.00, 5.50);

  -- Articles Finition
  INSERT INTO catalog.article (reference, designation, categorie_id, unite, prix_vente, prix_achat, tva) VALUES
    ('FIN-HUILE-LIN', 'Huile de lin 5L', v_cat_finition, 'u', 48.00, 35.00, 20.00),
    ('FIN-LASURE-5L', 'Lasure bois extérieur chêne 5L', v_cat_finition, 'u', 62.00, 42.00, 20.00);

  -- Prestations (services, pas de prix achat)
  INSERT INTO catalog.article (reference, designation, description, categorie_id, unite, prix_vente, tva) VALUES
    ('PREST-POSE-CHARP', 'Pose charpente traditionnelle', 'Main d''oeuvre pose charpente, hors fournitures', v_cat_presta, 'h', 55.00, 20.00),
    ('PREST-POSE-ISOL', 'Pose isolation laine de bois', 'Main d''oeuvre isolation, hors matériaux', v_cat_presta, 'm2', 18.00, 10.00);

  -- Un article inactif pour tester le filtre
  INSERT INTO catalog.article (reference, designation, categorie_id, unite, prix_vente, prix_achat, tva, actif) VALUES
    ('BOIS-EPIC-OLD', 'Épicéa 27mm (ancien)', v_cat_bois, 'm3', 900.00, 650.00, 20.00, false);
END;
$function$;
COMMENT ON FUNCTION catalog_qa.seed() IS 'Seed données démo: 5 catégories, ~15 articles (matériaux BTP, prestations artisan)';

GRANT USAGE ON SCHEMA catalog_qa TO anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA catalog_qa TO anon;
